def _build_cloner(self):
        conn, orig_name, new_name = self.conn.get_backend(), self.vm.get_name(), self.widget("clone-new-name").get_text()
        cloner = Cloner(conn, src_name=orig_name)
        if new_name:
            cloner.set_clone_name(new_name)
        return cloner

